import math
from ansible.errors import AnsibleFilterTypeError
from ansible.module_utils._text import to_native

def power(x, y):
    try:
        return math.pow(x, y)
    except TypeError as e:
        raise AnsibleFilterTypeError(f'pow() can only be used on numbers: {to_native(e)}')

