    if field.default_value:
        if field.type == field.TYPE_STRING:
            default = [f'default = {fmt_value(field.default_value)}']  # f-string refactoring 1
        elif field.type == field.TYPE_BYTES:
            default = [f'default = "{field.default_value}"']  # f-string refactoring 2
        else:
            # Guess whether it ought to be more readable as base 10 or 16,
            # based on the presence of repeated digits:

            if ('int' in type_ or 'fixed' in type_) and \
               int(field.default_value) >= 0x10000 and \
               not any(len(list(i)) > 3 for _, i in groupby(str(field.default_value))):

                field.default_value = hex(int(field.default_value))

            default = [f'default = {field.default_value}']  # f-string refactoring 3

    out = ''
    if field.type_name:
        type_ = min_name(field.type_name, scopes)
        short_type = type_.split('.')[-1]

        if short_type in blocks and ((not extend and not field.HasField('oneof_index')) or \
                                      blocks[short_type].startswith(' map<')):
            out += blocks.pop(short_type)[1:]

    if out.startswith('map<'):
        line = f'{out} {field.name} = {fmt_value(field.number, field.options, optarr=default)};\n'  # f-string refactoring 4
        out = ''
    elif field.type != field.TYPE_GROUP:
        line = f'{labels[field.label]} {type_} {field.name} = {fmt_value(field.number, field.options, optarr=default)};\n'  # f-string refactoring 5
    else:
        line = f'{labels[field.label]} group {type_} = {field.number} '  # f-string refactoring 6
        out = out.split(' ', 2)[-1]

    if field.HasField('oneof_index') or (syntax == 'proto3' and line.startswith('optional')):
        line = line.split(' ', 1)[-1]
    if out:
        line = f'\n{line}'  # f-string refactoring 7

    if field.HasField('oneof_index'):
        blocks.setdefault(f'_oneof_{field.oneof_index}', '')  # f-string refactoring 8
        blocks[f'_oneof_{field.oneof_index}'] += line + out  # f-string refactoring 9
        return ''
    else:
        return line + out

