        if not self.rocket:
            return
        email = user.email
        if email is None:
            email = "%s@rocketchat.com" % user.uuid
        account = self.rocket.users_create(
            email, user.name, password, user.handle.replace(" ", "_")
        ).json()
        self.create_team(user.team, account)

