        ), "component_begin must be <= component_end"

        assert (
            self.object_span == self.component_span
        ), f"object_span ({self.object_span}) must be same as component_span ({self.component_span})"

    else:
        assert self.gap_length >= 1, "gap_length must be >= 1"

        assert (
            self.object_span == self.gap_length
        ), f"object span ({self.object_span}) must be same as gap_length ({self.gap_length})"

        assert (
            self.gap_type in Valid_gap_type
        ), f"gap_type must be one of {'|'.join(Valid_gap_type)}, you have {self.gap_type}"

        assert all(
            x in Valid_evidence for x in self.linkage_evidence
        ), f"linkage_evidence must be one of {'|'.join(Valid_evidence)}, you have {self.linkage_evidence}"

        if self.linkage == "no":
            assert not self.linkage_evidence or self.linkage_evidence[0] in (
                "",
                "na",
            ), f"linkage no is incompatible with evidence {self.linkage_evidence}"

