def _updateBuildAge(self):
    """Update the build time and the fuzzy age."""
    if self.buildTime > 0:
        strBuildTime = f"{datetime.fromtimestamp(self.buildTime).strftime('%x %X')} ({fuzzyTime(time() - self.buildTime)})"
    else:
        strBuildTime = self.tr("Unknown")

    self.theTitle.setText(self.tr(f"<b>Build Time:</b> {strBuildTime}"))

    return

